+                html_url: "".to_string(),
+                body: Some("Draft notes".to_string()),
+                assets: vec![],
+                published_at: None,
+            },
+            ReleaseInfo {
+                tag_name: "v1.0.0".to_string(),
+                name: "Current".to_string(),
+                prerelease: false,
+                draft: false,
+                html_url: "".to_string(),
+                body: Some("Current release".to_string()),
